INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-b20a8cf8-moex-00224', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關司法警察官或司法警察執行拘提之規定，下列敘述何者正確？', '["刑事訴訟法第77條第1項規定，拘提應用拘票，故於司法警察官或司法警察合法通知犯罪嫌 疑人到場詢問，而其無正當理由不到場者，得依該條之規定，向法院聲請拘票拘提之", "犯罪嫌疑人甲犯罪嫌疑重大，且有事實足認為有逃亡之虞，必要時，依刑事訴訟法第76條之 規定，司法警察官或司法警察得不經傳喚逕行拘提", "犯罪嫌疑人乙因蛇行駕車遭到警員盤查，警員因聞到濃厚酒味，遂要求其進行呼氣測試；乙因 心虛而拒絕做測試，隨即駕車逃逸。由於突發之緊急情況、不及報告檢察官，警員可依刑事訴 訟法第88條之1，逕行拘提乙", "司法警察官或司法警察依刑事訴訟法第88條之1執行逕行拘提後，應即將執行經過情形陳報 所屬司法警察機關主管長官；為便利起見，於移送犯罪嫌疑人時，始一併將書面連同有關資料， 報請執行地之該管檢察官簽發拘票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00225', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警方查獲16歲少年甲，以竊得機車為作案工具四處行搶，並以現行犯逮捕之。試問下列對於本 案之少年事件處理，何者正確？', '["由於甲所犯之罪為刑法第325條第1項搶奪罪，最重本刑為5年以下有期徒刑，應依刑法及刑 事訴訟法之規定，移送該管地方法院", "由於甲係遭警察機關以現行犯逮捕，為保障未成年人之權利，無論是否有合法通知、亦無論有 無正當理由不到場，警察機關在甲之法定代理人、現在保護少年之人或其他適當之人到場前， 均不得詢問甲", "依法應於24小時內護送少年至少年法院（庭）之事件，等候甲之法定代理人、現在保護少年 之人或其他適當陪同之人到場之時間不予計入，惟應釋明其事由。但等候時間合計不得逾4小時", "警方應先對甲進行人別確認，其次進行告知義務，之後始得進行本案之詢問；詢問甲原則上不 得於夜間為之，但若於日間已開始詢問者，得繼續至夜間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00226', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於調取通信紀錄及通訊監察之活動，下列敘述何者正確？', '["警員為偵辦刑法第306條第1項侵入住宅罪之案件，認為有調取通信紀錄之必要，即依通訊保 障及監察法規定，報請檢察官許可後，向該管法院聲請核發調取票", "警員為偵辦詐欺罪案件，認為有調取通信紀錄之必要，即依通訊保障及監察法規定，向檢察官 聲請同意後，調取通信紀錄", "為利掌握調取情形，各警察機關之通訊監察組應於每月1日前，將前1個月之調取統計數據， 製作統計表並簽陳主官核閱，另各警察機關並應按月將調取通信紀錄及使用者資料之筆數及核 銷經費等統計資料，函送內政部警政署刑事警察局彙整", "調取通信紀錄或使用者資料等，除因案件偵辦目的有必要長期留存者外，可報請所屬單位主管核 准後建檔永久保留。調取後發現全部資料與調取目的無關者，得經所屬單位主管核准後銷毀之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00227', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '對使用於網路犯罪之電腦執行扣押時，應注意事項，下列何者錯誤？', '["執行扣押時以扣押整套電腦設備為宜，包含電腦主機、螢幕、鍵盤、電源線等設備", "扣押電腦應符合比例原則，尤其網路公司應特別注意其影響層面", "扣押電腦物品時，考慮到其容易毀損的特性，應另行準備包材，綑綁打包，更須小心拆裝搬運", "磁碟片、光碟片等電腦輔助記憶體之數量應確實清點，並詳載於扣押物品目錄表"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00228', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '轄區發生運鈔車於途中遭攔車強盜案件，在犯罪偵查中，相對而言，下列何者較無進行偵查之必 要性及價值性？', '["該運鈔車保全財務狀況", "該運鈔車當日運鈔路線", "歹徒犯案地點及逃逸路線", "運鈔銀行間之營業額比較"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00229', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關司法警察執行拘提的敘述，下列何者錯誤？', '["犯罪嫌疑重大而無一定之住居所者，得不經通知，報請檢察官簽發拘票執行", "執行拘提時，應當場告知拘提之原因，抗拒拘提者得用強制力，但不得逾必要之程度", "因目擊者之供述，且有事實足認為嫌疑重大，情況急迫不及報告檢察官者，得逕行拘提", "拘提現役軍人，應知照該管機關長官協助執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00230', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '根據警察偵查犯罪手冊之規定，關於偵查守則之說明，下列何者錯誤？', '["為貫徹法治原則，司法警察官或司法警察偵查犯罪時，任何情況均應穿著制服或刑警背心，或 出示足資識別之證件或警徽，並告知事由", "偵查犯罪，應遵守偵查不公開之規定，不得將因執行職務知悉之事項，公開或揭露予執行法定 職務必要範圍以外之人員", "偵查犯罪應以現場為基礎，運用科學器材與方法，合法取證", "為保護檢舉犯罪或提供破案線索之人之名譽、隱私或安全，不得公開或揭露足資識別其身分之資 訊，並應遵守證人保護法或偵查不公開作業辦法等關於保護證人、檢舉人或被害人之相關規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00231', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於重大刑案之敘述，下列何者正確？', '["所稱重大刑案有三：犯罪手段殘酷、情節離奇案件；新發現嚴重犯罪手法，必須迅速偵破，予 以遏制之案件；以及深切影響社會治安、震撼社會人心之案件", "重大刑案應由署長指派刑事警察局主動支援，全面協調、統一指揮，合力偵辦。刑事警察局得 不經申請逕行派員指導支援偵辦", "重大或特殊刑案發生後，承辦警局若不能即時獲得線索予以偵破，而必須有關單位協助偵查時， 得成立專案小組負責偵查", "未破重大刑案，經專案管制3年後，仍未偵破者，應將有關該案之文書、證據等相關卷宗及證 物清冊併同未破重大刑案偵查報告書專卷建檔，並指定專責承辦人以專櫃或專有空間妥善保 存，定期分析及整理相關卷宗及證物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00232', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '關於自首之說明，下列何者錯誤？', '["犯罪行為人對未被發覺之犯罪，親自或委託他人，向檢察官或警察機關自承犯罪事實，並表明 願受法律裁判者，為自首", "如該管有偵查權之公務員有任何一人已知悉犯罪嫌疑人時，但犯罪嫌疑人對已被發覺之犯罪坦 誠供述者，仍生自首之效力", "受理自首時，應詢明犯罪嫌疑人欲主動告知之犯罪行為，並載明於筆錄", "自首案件應注意是否為他人頂替，或有無不正當之企圖，及其身心是否正常，以防疏誤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00233', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察甲為查緝運送走私菸，擅自裝置 GPS 衛星定位追蹤器於乙停放其家門前路邊之貨車下方底 盤，用以接收乙之貨車所在位置之經緯度、地址及停留時間等行蹤數據，並記錄下來。根據我國 法院之見解，下列說明何者錯誤？', '["雖然 GPS 位置訊息是零散且多數訊息是「公共場所」的位置資訊，但大法官與法院認為，將 GPS所得的所有位置資訊一起觀察後，能夠相當程度了解被跟監人之生活隱私，故GPS偵查 所獲得的位置資訊構成「非公開之活動」", "運用 GPS 偵查之目的，乃在於蒐集人民「非公開」的位置資訊，透過拼湊大量位置資訊可以 描繪出被監控人民之生活軌跡，故已經侵害「隱私權」，所以該偵查行為之性質為「強制處分」", "最高法院認為，「無故」指的是「無法律上正當理由」，行為的目的就算正當不等於「有故」； 再加上現行沒有任何法律可以當作GPS偵查的法律依據，所以警察裝設GPS偵查犯罪並未具 有法律上正當理由", "目前法院實務上認為員警在私人車輛裝上GPS偵查犯罪，構成刑法第315條之1第2款的「竊 錄罪」，但因為警察係為偵查犯罪之故，而可以主張刑法第21條第1項之依法令之行為而阻 卻違法，其行為不罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
